        let url = `/ext/retail-auth/ui/profile-redirect?application_id=${app_id}&return_ui_url=${return_ui_url}`
        window.location.replace(url);
    }
}

(function () {
  var details = document.querySelectorAll('.staticcontent details');

  details.forEach(function (detail) {
    detail.addEventListener('toggle', function () {
      if (!this.open) return;

      details.forEach(function (other) {
        if (other === detail) return;

        var iframe = other.querySelector('iframe.yt_player_iframe');
        if (iframe) {
          var src = iframe.src;
          iframe.src = '';
          iframe.src = src;
        }

        other.open = false;
      });
    });
  });
})();

