function UCP_JSON_Formatter(event= "", eventData={},type=""){
    let data = {};
    if(eventData?.product){
        data = eventData?.product ;
    }
    if((eventData?.products !== undefined && eventData?.products != null) && eventData?.products.length > 0) {
        data = eventData?.products[0];
    }
    let extraData = eventData?.product_extra_data;
    let userdata = {}; 
    let rrid = '';
    let userid = '';
    let userauth = '';
    let productJson = {};
    let cart_add_detail=[];
    let l1_category = "";
    let l2_category = "";
    let l3_category = "";
    let l4_category = "";
    let l5_category = "";
    let l1_id = "";
    let l2_id = "";
    let l3_id = "";
    let l4_id = "";
    let l5_id = "";
    let cartid=0;
    let cartinfo={};
    let verticalCode = "";
    let imageUrl = "";
    let price = 0;
    let dimension_data = {};
    if(eventData?.cart_id){
        cartid = eventData?.cart_id;
    }
    // if(action=='remove' && prodqty==0){
    //   prodqty=1;
    // }
    if(window.FPI?.state?.user?._data){
        userdata = window.FPI?.state?.user?._data?.user ? window.FPI?.state?.user?._data?.user : {}; 
        rrid= userdata.rr_id ? userdata.rr_id : '';
        userid= userdata.user_id ? userdata.user_id : '';
        userauth = localStorage.getItem('userauth') ? localStorage.getItem('userauth') : '';
    }
    // if(data != null && userdata != '' && rrid != '' && userid != '' && userauth != ''){

        let product_id = data?.uid ? data.uid.toString() : '';
        if(data?.categories){
            l1_category = ((data?.categories[0]?.name.split('::')).length > 0) ? ((data.categories[0].name.split('::')[0] != undefined && data.categories[0].name.split('::')[0] != null) ? data.categories[0].name.split('::')[0] : ""): "";
            l2_category = ((data?.categories[0].name.split('::')).length > 0) ? ((data.categories[0].name.split('::')[1] != undefined && data.categories[0].name.split('::')[1] != null) ? data.categories[0].name.split('::')[1] : ""): "";
            l3_category = ((data?.categories[0].name.split('::')).length > 1) ? ((data.categories[0].name.split('::')[2] != undefined && data.categories[0].name.split('::')[2] != null) ? data.categories[0].name.split('::')[2] : ""): "";
            l4_category = ((data?.categories[0].name.split('::')).length > 2) ? ((data.categories[0].name.split('::')[3] != undefined && data.categories[0].name.split('::')[3] != null) ? data.categories[0].name.split('::')[3] : ""): "";
            l5_category = ((data?.categories[0].name.split('::')).length > 3) ? ((data.categories[0].name.split('::')[4] != undefined && data.categories[0].name.split('::')[4] != null) ? data.categories[0].name.split('::')[4] : ""): "";
        }
        if(type == "Product Viewed") {
            if(FPI?.state?.product?._data?.product){
                if(FPI?.state?.product?._data?.product?.uid == product_id){
                    if(FPI?.state?.product?._data?.product?.category_map){
                        l2_id = ((FPI?.state?.product?._data?.product?.category_map?.l1 != undefined && FPI?.state?.product?._data?.product?.category_map?.l1 != null)) ? FPI?.state?.product?._data?.product?.category_map?.l1?.uid : "";
                        l3_id = ((FPI?.state?.product?._data?.product?.category_map?.l2 != undefined && FPI?.state?.product?._data?.product?.category_map?.l2 != null)) ? FPI?.state?.product?._data?.product?.category_map?.l2?.uid : "";
                        l4_id = ((FPI?.state?.product?._data?.product?.category_map?.l3 != undefined && FPI?.state?.product?._data?.product?.category_map?.l3 != null)) ? FPI?.state?.product?._data?.product?.category_map?.l3?.uid : "";
                        l5_id = ((FPI?.state?.product?._data?.product?.category_map?.l4 != undefined && FPI?.state?.product?._data?.product?.category_map?.l4 != null)) ? FPI?.state?.product?._data?.product?.category_map?.l4?.uid : "";
                    }
                    if(FPI?.state?.product?._data?.product?.department){
                        l1_id = FPI?.state?.product?._data?.product?.department?.uid;
                    }
                    if(FPI?.state?.product?._data?.product){
