            l4_category = ((data?.category.name.split('::')).length > 2) ? ((data?.category?.name.split('::')[3] != undefined && data?.category?.name.split('::')[3] != null) ? data?.category?.name.split('::')[3] : ""): "";
            l5_category = ((data?.category.name.split('::')).length > 3) ? ((data?.category?.name.split('::')[4] != undefined && data?.category?.name.split('::')[4] != null) ? data?.category?.name.split('::')[4] : ""): "";
