                    l2_category =  (categories.length > 2) ? (categories[2]?.name || "") : "";
                    l3_category =  (categories.length > 3) ? (categories[3]?.name || "") : "";
                    l4_category =  (categories.length > 4) ? (categories[4]?.name || "") : "";
                    l5_category =  (categories.length > 5) ? (categories[5]?.name || "") : "";

