                    l2_id = (categories.length > 2) ? (categories[2]?.source_id || "") : "";
                    l3_id = (categories.length > 3) ? (categories[3]?.source_id || "") : "";
                    l4_id = (categories.length > 4) ? (categories[4]?.source_id || "") : "";
                    l5_id = (categories.length > 5) ? (categories[5]?.source_id || "") : "";
