            if(data?.price_per_unit?.converted?.effective?.max){
                price = Number(data?.price_per_unit?.converted?.effective?.max.toFixed(2)) ; 
            } else {
                price = Number(data?.price_per_unit?.converted?.effective.toFixed(2)) ; 
            }
        }

        let currencyCode = data?.price?.effective?.currency_code || "INR";

        if(data?.price?.currency_code){
            currencyCode = data?.price?.currency_code || "INR";
        }

        let productUrl = '/product/'+data.slug;
        if(data?.source_url){
            productUrl = data?.source_url;
        }
        if(data?.attributes){
            verticalCode  = data?.attributes['vertical-code'] || '';
        }

        if(window.FPI?.state?.product?.selectedArticle?._data?.items.length > 0){
            if(window.FPI?.state?.product?.selectedArticle?._data?.items[0]?._custom_json?.vertical_code){
                verticalCode = window.FPI?.state?.product?.selectedArticle?._data?.items[0]?._custom_json?.vertical_code || "";
            }
        }
        if(type == "Product Viewed") {
            if(FPI?.state?.product?._data?.product){
                if(FPI?.state?.product?._data?.product?.uid == product_id){
                    if(FPI?.state?.product?._data?.product?.attributes){
                        var fpi_attr_entries = Object.entries(FPI?.state?.product?._data?.product?.attributes);
                        fpi_attr_entries.map(([fpi_attrIndex, fpi_attrItem] = attr_entry) => {
                            if(fpi_attrIndex == "vertical-code"){
                                verticalCode = fpi_attrItem;
                            }
                        });
                    }
                }
            }
        }
        if((data?.medias != undefined && data?.medias != null) && data?.medias.length > 0){
