        }
        if(window.FPI?.state?.product?.selectedArticle?._data?.items.length > 0){
            if(window.FPI?.state?.product?.selectedArticle?._data?.items[0]?._custom_json?.attributes?.image_groups['Product Images']?.images.length > 0){
