            }
        }

        productJson = {
            "external_ids":[
                {
                "type": "rr_id",
                "id": rrid
                }
            ],
            "application_ids":[
                {
                "type": "jiomart_id",
                "id": userid
                }
            ],
            "meta": {
                "session_id": userauth
                // "widget_id": "",
                // "widget_source_type": listname+"|mylist"
            },
            "click_source": click_source,
            "product_id": product_id,
            "product_name": productName,
            "sku": sku_raw,
            "l1_category": l1_category,//productInfo?.categorylevel?.level1?.length > 0 ? productInfo.categorylevel.level1[0] : '',
            "l1_category_id": l1_id,
            "l2_category": l2_category,
            "l2_category_id": l2_id,
            "l3_category": l3_category,
            "l3_category_id": l3_id,
            "l4_category": l4_category,
            "l4_category_id": l4_id,
            "l5_category": l5_category,
            "l5_category_id": l5_id,
            "brand": brand,
            "brand_id": brand_id,
            "quantity": 1,
            "price": price,
            "value": price, // need to update Number(data.price.marked.max.toFixed(2))
            "currency": currencyCode,
            "url": productUrl,
            "verticalcode": verticalCode,
            "img_url": imageUrl //productInfo?.image?(productInfo.image):Configs.ANG_URL+"/images/product/original/"+productInfo.product_image_path
        };
        if(cartid){
            productJson.cart_id = cartid;
        }
    // }
    return productJson;
}
