(() => {

  const customCONFIG = {
    OBSERVER_ROOT_MARGIN: '50px 0px',
    OBSERVER_THRESHOLD: [0.1, 0.5, 1.0],
    PERIODIC_CHECK_INTERVAL: 1000,
    PERIODIC_CHECK_MAX: 60,
    HIGHLIGHT_DURATION: 2000,
    BADGE_DURATION: 3000,
    SLIDE_RECHECK_DEBOUNCE: 100
  };


  const customPAGE_TYPES = {
    HOME: 'home',
    PLP: 'product-listing',
    COLLECTION: 'collection-listing',
    PDP: 'product-description',
    SEARCH: 'search',
    CART: 'cart',
    WISHLIST: 'wishlist',
    SECTION: 'section',
    OTHER: 'other'
  };

  const customDetectPageType = () => {
    const pathname = window.location.pathname;
    const pageTitle = (document.title || '').toLowerCase();
    const searchParams = new URLSearchParams(window.location.search);

    // Home page
    if (pathname === '/' || pathname === '') {
      return customPAGE_TYPES.HOME;
    }

    // PDP - Product Description Page
    if (pathname.includes('/product/') || pathname.match(/\/p\/[^\/]+$/)) {
      return customPAGE_TYPES.PDP;
    }

    // Search page
    if (searchParams.has('q') || pathname.includes('/search')) {
      return customPAGE_TYPES.SEARCH;
    }

    // Collection page
    if (pathname.includes('/collection/') || pathname.includes('/c/')) {
      return customPAGE_TYPES.COLLECTION;
    }

    // PLP - Product Listing Page
    if (pathname.includes('/products') || pathname.includes('/category/')) {
      return customPAGE_TYPES.PLP;
    }

    // Cart page
    if (pathname.includes('/cart') || pageTitle.includes('cart')) {
      return customPAGE_TYPES.CART;
    }

    // Wishlist page
    if (pathname.includes('/wishlist') || pageTitle.includes('wishlist')) {
      return customPAGE_TYPES.WISHLIST;
    }

    // Section page
    if (pathname.includes('/section/') || pathname.includes('/sections/')) {
      return customPAGE_TYPES.SECTION;
    }

    return customPAGE_TYPES.OTHER;
  };


  const customState = {
    pageType: customDetectPageType(),
    trackedImpressions: new Set(),
    trackedClicks: new Set(),
    trackedAdspotIds: new Set(),
    trackedEvents: [],
    eventCounter: 0,
    adElements: [],
    observer: null,
    intervalId: null,
    startTime: Date.now()
  };






  const customExtractUvFromUrl = (url) => {
    try {
      const urlParams = new URL(url, window.location.origin).searchParams;
      return urlParams.get('uv') || '';
    } catch (e) {
      const match = /[?&]uv=([^&]+)/.exec(url);
      return match && match[1] ? match[1] : '';
    }
  };

  const customExtractAdCampaignId = (url) => {
    const match = /adcampaignid=([^&]+)/.exec(url);
    return match && match[1] ? match[1] : '';
  };

  const customGetPageData = () => {
    let pincode = '';
    try { pincode = parseInt(localStorage.getItem('pincode')) || ''; } catch (e) {}

    const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

    // Get login status
    let loginStatus = 'not logged in';
    try {
      const customerData = localStorage.getItem('customer_data');
      if (customerData) {
        const parsed = JSON.parse(customerData);
        if (parsed && parsed.isLoggedIn) {
          loginStatus = 'logged in';
        }
      }
    } catch (e) {}

    return {
      pincode,
      pageType: customState.pageType,
      platform: isMobile ? 'msite' : 'website',
      loginStatus,
      journey: localStorage.getItem('journey') || window.journeyData || ''
    };
  };



  const customAD_SELECTORS = {
    // Common selectors for all pages
    common: [
      'ins[data-adspot-key]',
      '[data-adspot-key]',
      'iframe[id*="jioads"]',
      'iframe[src*="jioads"]',
      'iframe[src*="jioad"]',
      '.jioads-container',
      '[class*="jioads"]',
      '[id*="jioads"]'
    ],

    // Page-specific selectors
    [customPAGE_TYPES.HOME]: [
      '[id*="home_ads"]',
      '[id*="homepage_ads"]',
      '[class*="hero-banner"] ins',
      '[class*="banner-carousel"] ins',
      '.hero-banner ins[data-adspot-key]',
      '[class*="ads-banner"]',
      '[class*="sponsored"]'
    ],

    [customPAGE_TYPES.PLP]: [
      '[id*="plp_ads"]',
      '[id*="listing_ads"]',
      '[class*="product-listing"] ins[data-adspot-key]',
      '[class*="sponsored-product"]',
      '.listing-ads-container',
      '[id*="products_ads"]'
    ],

    [customPAGE_TYPES.COLLECTION]: [
      '[id*="collection_ads"]',
      '[id*="clp_ads"]',
      '[class*="collection-listing"] ins[data-adspot-key]',
      '[class*="collection-banner"] ins',
      '.collection-ads-container'
    ],

    [customPAGE_TYPES.PDP]: [
      '[id*="pdp_ads_ds2"]',
      '[id*="pdp_ads"]',
      '[class*="product-description"] ins[data-adspot-key]',
      '[class*="pdp-ads"]',
      '.pdp-jioads-container',
      '[class*="similar-products"] ins[data-adspot-key]'
    ],

    [customPAGE_TYPES.SEARCH]: [
      '[id*="search_ads"]',
      '[id*="srp_ads"]',
      '[class*="search-results"] ins[data-adspot-key]',
      '.search-ads-container'
    ],

    [customPAGE_TYPES.CART]: [
      '[id*="cart_ads"]',
      '[class*="cart"] ins[data-adspot-key]',
      '.cart-ads-container'
    ],

    [customPAGE_TYPES.OTHER]: []
  };



  const customPushJioAdsGtmEvent = (type, campaignId, adspotId, slideIndex = null) => {
    const d = customGetPageData();

    const eventData = {
      event: 'event_jioads',
      journey: d.journey,
      category: 'jioads',
      action: type === 'click' ? 'banner clicked' : 'banner impression',
      label: type === 'click' ? 'jioads_banner_clicked' : 'jioads_banner_seen',
      jioads_campaign_id: campaignId,
      pincode: d.pincode,
      page_type: d.pageType,
      platform: d.platform,
      login_status: d.loginStatus
    };

    if (slideIndex !== null) {
      eventData.slide_index = slideIndex;
    }

    customState.eventCounter++;
    customState.trackedEvents.push({ 
      id: customState.eventCounter, 
      timestamp: new Date().toISOString(),
      elapsedMs: Date.now() - customState.startTime,
      ...eventData 
    });

    // Push to dataLayer
    window.dataLayer = window.dataLayer || [];
    window.dataLayer.push(eventData);

    // Log to console
    const icon = type === 'impression' ? '[IMP]' : '[CLK]';

    console.table({
      'Event': eventData.event,
      'Action': eventData.action,
      'Campaign ID': campaignId,
      'Adspot ID': adspotId,
      'Page Type': eventData.page_type,
      'Platform': eventData.platform,
      'Slide Index': slideIndex !== null ? slideIndex : 'N/A'
    });

    return eventData;
  };



  const customIsInActiveSlide = (element) => {
    // Check Swiper slides
    const swiperSlide = element.closest('.swiper-slide');
    if (swiperSlide) {
      const isActive = swiperSlide.classList.contains('swiper-slide-active');
      const isVisible = swiperSlide.classList.contains('swiper-slide-visible');
      const isNext = swiperSlide.classList.contains('swiper-slide-next');
      const isPrev = swiperSlide.classList.contains('swiper-slide-prev');
      return isActive || isVisible || isNext || isPrev;
    }

    // Check generic carousel patterns
    const carouselItem = element.closest('[class*="carousel-item"], [class*="slide"], [class*="banner-item"]');
    if (carouselItem) {
      const classList = Array.from(carouselItem.classList);
      return classList.some(cls => 
        cls.includes('active') || cls.includes('visible') || cls.includes('current')
      );
    }

    return true; // Not in a carousel
  };

  const customGetSlideIndex = (element) => {
    const swiperSlide = element.closest('.swiper-slide');
    if (swiperSlide) {
      const swiper = swiperSlide.closest('.swiper');
      if (swiper) {
        const slides = swiper.querySelectorAll('.swiper-slide');
        return Array.from(slides).indexOf(swiperSlide);
      }
    }

    const carouselItem = element.closest('[class*="carousel-item"], [class*="slide"], [class*="banner-item"]');
    if (carouselItem && carouselItem.parentElement) {
      return Array.from(carouselItem.parentElement.children).indexOf(carouselItem);
    }

    return -1;
  };



  const customFindAllJioAdsElements = () => {
    const elements = new Map(); // Use Map to dedupe by element

    // Get selectors for current page type + common selectors
    const pageSelectors = customAD_SELECTORS[customState.pageType] || [];
    const allSelectors = [...customAD_SELECTORS.common, ...pageSelectors];

    // Query all selectors
    allSelectors.forEach(selector => {
      try {
        document.querySelectorAll(selector).forEach(el => {
          if (!elements.has(el)) {
            const adspotKey = el.getAttribute('data-adspot-key') || el.id || selector;
            elements.set(el, {
              element: el,
              type: customGetElementType(el),
              adspotKey: adspotKey,
              id: el.id || '',
              selector: selector,
              pageType: customState.pageType
            });
          }
        });
      } catch (e) {
        // Invalid selector, skip
      }
    });

    return Array.from(elements.values());
  };

  const customGetElementType = (el) => {
    if (el.tagName === 'INS') return 'ins';
    if (el.tagName === 'IFRAME') return 'iframe';
    if (el.id && el.id.includes('ads')) return 'container';
    if (el.className && el.className.includes('jioads')) return 'jioads-container';
    return 'element';
  };



  const customCheckElementForImpressionUrls = (element) => {
    const urls = [];

    // Check images in element
    element.querySelectorAll('img').forEach(img => {
      const src = img.src || img.getAttribute('src') || img.getAttribute('data-src') || '';
      if (src.includes('ADSIMPRESSION') || src.includes('uv=')) {
        urls.push({ type: 'image', src, element: img });
      }
    });

    // Check iframes
    element.querySelectorAll('iframe').forEach(iframe => {
      try {
        const doc = iframe.contentDocument || iframe.contentWindow?.document;
        if (doc) {
          doc.querySelectorAll('img').forEach(img => {
            const src = img.src || '';
            if (src.includes('ADSIMPRESSION') || src.includes('uv=')) {
              urls.push({ type: 'iframe-image', src, element: img });
            }
          });

          doc.querySelectorAll('a').forEach(a => {
            const href = a.href || '';
            if (href.includes('ADSIMPRESSION') || href.includes('adcampaignid=')) {
              urls.push({ type: 'iframe-link', src: href, element: a });
            }
          });
        }
      } catch (e) {
        // CORS restriction
        urls.push({ type: 'iframe-cors', src: iframe.src, element: iframe });
      }
    });

    // Check links
    element.querySelectorAll('a').forEach(a => {
      const href = a.href || '';
      if (href.includes('ADSIMPRESSION') || href.includes('adcampaignid=')) {
        urls.push({ type: 'link', src: href, element: a });
      }
    });

    // Check for data attributes with URLs
    const dataSrc = element.getAttribute('data-impression-url') || element.getAttribute('data-tracking-url');
    if (dataSrc && (dataSrc.includes('ADSIMPRESSION') || dataSrc.includes('uv='))) {
      urls.push({ type: 'data-attr', src: dataSrc, element: element });
    }

    return urls;
  };



  const customTrackImpression = (adInfo, impressionUrl) => {
    const slideIndex = customGetSlideIndex(adInfo.element);
    const key = adInfo.adspotKey + '_' + slideIndex + '_' + impressionUrl.src.substring(0, 50);

    if (customState.trackedImpressions.has(key)) {
      return false;
    }

    // Check if in active slide
    if (!customIsInActiveSlide(adInfo.element)) {
      return false;
    }

    customState.trackedImpressions.add(key);

    // Extract campaign ID
    var campaignId = customExtractUvFromUrl(impressionUrl.src);
    if (!campaignId) {
      campaignId = customExtractAdCampaignId(impressionUrl.src);
    }

    if (campaignId) {
      // Avoid duplicate events from same adspot ID
      if (customState.trackedAdspotIds.has(adInfo.adspotKey)) {
        return false;
      }
      customState.trackedAdspotIds.add(adInfo.adspotKey);

      customPushJioAdsGtmEvent('impression', campaignId, adInfo.adspotKey, slideIndex >= 0 ? slideIndex : null);
      return true;
    }

    return false;
  };



  const customSetupClickTracking = () => {
    document.addEventListener('click', function(e) {
      var target = e.target;
      var linkElement = null;

      if (target.tagName === 'A') {
        linkElement = target;
      } else {
        linkElement = target.closest('a');
      }

      if (linkElement && linkElement.href) {
        var href = linkElement.href;
        if (href.includes('adcampaignid=')) {
          var campaignId = customExtractAdCampaignId(href);
          if (campaignId && !customState.trackedClicks.has(campaignId)) {
            customState.trackedClicks.add(campaignId);

            // Find adspot key from parent
            var adContainer = linkElement.closest('[data-adspot-key]') || linkElement.closest('[id*="ads"]');
            var adspotKey = adContainer ? (adContainer.getAttribute('data-adspot-key') || adContainer.id) : 'unknown';

            // Avoid duplicate click events from same adspot ID
            var clickKey = 'click_' + adspotKey;
            if (customState.trackedAdspotIds.has(clickKey)) {
              return;
            }
            customState.trackedAdspotIds.add(clickKey);

            customPushJioAdsGtmEvent('click', campaignId, adspotKey);
          }
        }
      }
    }, true);
  };



  const customSetupViewportTracking = () => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting && entry.intersectionRatio > 0.1) {
          const adInfo = entry.target._customAdInfo;
          if (!adInfo) return;



          const impressionUrls = customCheckElementForImpressionUrls(entry.target);

          if (impressionUrls.length > 0) {
            impressionUrls.forEach(url => customTrackImpression(adInfo, url));
          } else {

            if (!customState.trackedImpressions.has(adInfo.adspotKey)) {
              customState.trackedImpressions.add(adInfo.adspotKey);
            }
          }
        }
      });
    }, {
      root: null,
      rootMargin: customCONFIG.OBSERVER_ROOT_MARGIN,
      threshold: customCONFIG.OBSERVER_THRESHOLD
    });

    return observer;
  };



  const customSetupSlideChangeListener = () => {
    let recheckTimeout = null;

    const customRecheckAllImpressions = () => {
      if (recheckTimeout) clearTimeout(recheckTimeout);

      recheckTimeout = setTimeout(() => {
        customState.adElements.forEach(ad => {
          const impressionUrls = customCheckElementForImpressionUrls(ad.element);
          impressionUrls.forEach(url => customTrackImpression(ad, url));
        });
      }, customCONFIG.SLIDE_RECHECK_DEBOUNCE);
    };

    // Listen for Swiper transition end
    document.addEventListener('transitionend', (e) => {
      const target = e.target;
      if (target.classList?.contains('swiper-slide') || 
          target.closest?.('.swiper-slide') ||
          target.closest?.('.swiper-wrapper')) {
        customRecheckAllImpressions();
      }
    });

    // Custom events
    ['slideChange', 'swiperSlideChange', 'carousel:change'].forEach(eventName => {
      document.addEventListener(eventName, customRecheckAllImpressions);
    });
  };



  const customInit = () => {
    // Find all JioAds elements
    customState.adElements = customFindAllJioAdsElements();



    if (customState.adElements.length === 0) {


    }

    // Log found elements grouped by type
    const grouped = customState.adElements.reduce((acc, ad) => {
      acc[ad.type] = acc[ad.type] || [];
      acc[ad.type].push(ad);
      return acc;
    }, {});

    Object.entries(grouped).forEach(([type, ads]) => {

      ads.forEach((ad, i) => {

      });
    });

    // Setup observer
    customState.observer = customSetupViewportTracking();

    // Observe all ad elements
    customState.adElements.forEach(ad => {
      ad.element._customAdInfo = ad;
      customState.observer.observe(ad.element);

      // Check immediately if in viewport
      const rect = ad.element.getBoundingClientRect();
      const isInViewport = (
        rect.top >= -50 &&
        rect.bottom <= window.innerHeight + 50
      );

      if (isInViewport) {
        const impressionUrls = customCheckElementForImpressionUrls(ad.element);
        impressionUrls.forEach(url => customTrackImpression(ad, url));
      }
    });

    // Setup click tracking
    customSetupClickTracking();

    // Setup slide change listener
    customSetupSlideChangeListener();

    // Periodic re-check
    let checkCount = 0;
    customState.intervalId = setInterval(() => {
      checkCount++;

      // Check existing ads
      customState.adElements.forEach(ad => {
        const rect = ad.element.getBoundingClientRect();
        const isInViewport = (
          rect.top >= -50 &&
          rect.bottom <= window.innerHeight + 50
        );

        if (isInViewport) {
          const impressionUrls = customCheckElementForImpressionUrls(ad.element);
          impressionUrls.forEach(url => customTrackImpression(ad, url));
        }
      });

      // Check for newly added ads
      const newAds = customFindAllJioAdsElements();
      newAds.forEach(ad => {
        if (!ad.element._customAdInfo) {
          ad.element._customAdInfo = ad;
          customState.observer.observe(ad.element);
          customState.adElements.push(ad);

        }
      });

      if (checkCount >= customCONFIG.PERIODIC_CHECK_MAX) {
        clearInterval(customState.intervalId);

      }
    }, customCONFIG.PERIODIC_CHECK_INTERVAL);

    return customState;
  };



  const customDebuggerInstance = customInit();

  window.customJioAdsDebugger = {
    // Status and info
    customStatus: function() {
      console.table({
        'Page Type': customState.pageType,
        'Total Ads Found': customState.adElements.length,
        'Impressions Tracked': customState.trackedImpressions.size,
        'Clicks Tracked': customState.trackedClicks.size,
        'Unique Adspots Fired': customState.trackedAdspotIds.size,
        'GTM Events Fired': customState.eventCounter,
        'Running Time': Math.round((Date.now() - customState.startTime) / 1000) + 's'
      });
    },

    // List all events
    customEvents: () => {
      if (customState.trackedEvents.length === 0) {
        return;
      }

      console.table(customState.trackedEvents.map(e => ({
        '#': e.id,
        'Type': e.action,
        'Campaign ID': e.jioads_campaign_id,
        'Adspot': e.adspot_id,
        'Page': e.page_type,
        'Time': `+${e.elapsedMs}ms`
      })));
    },

    // Rescan for new ads
    customRescan: () => {

      const newAds = customFindAllJioAdsElements();
      let addedCount = 0;

      newAds.forEach(ad => {
        if (!ad.element._customAdInfo) {
          ad.element._customAdInfo = ad;
          customState.observer.observe(ad.element);
          customState.adElements.push(ad);
          addedCount++;
        }
      });


    },

    // Check dataLayer
    customCheckDataLayer: () => {
      const jioAdsEvents = (window.dataLayer || []).filter(d => d?.event === 'event_jioads');


      if (jioAdsEvents.length > 0) {
        console.table(jioAdsEvents.map((e, i) => ({
          '#': i + 1,
          'Action': e.action,
          'Campaign ID': e.jioads_campaign_id,
          'Page Type': e.page_type,
          'Adspot': e.adspot_id
        })));
      }
    },

    // Force check all ads
    customForceCheck: () => {

      customState.adElements.forEach(ad => {
        const impressionUrls = customCheckElementForImpressionUrls(ad.element);

        impressionUrls.forEach(url => {

          customTrackImpression(ad, url);
        });
      });
    },

    // Scroll to ads
    customScrollToAds: () => {
      const firstAd = customState.adElements[0]?.element;
      if (firstAd) {
        firstAd.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else {

      }
    },

    // List all ad elements
    customListAds: () => {

      console.table(customState.adElements.map((ad, i) => ({
        '#': i + 1,
        'Type': ad.type,
        'Adspot Key': ad.adspotKey,
        'ID': ad.id || '-',
        'Selector': ad.selector,
        'Tracked': customState.trackedImpressions.has(ad.adspotKey) ? 'Yes' : '-'
      })));
    },

    // Get page type
    customGetPageType: () => {

      return customState.pageType;
    },

    // Reset tracking
    customReset: function() {
      customState.trackedImpressions.clear();
      customState.trackedClicks.clear();
      customState.trackedAdspotIds.clear();
      customState.trackedEvents.length = 0;
      customState.eventCounter = 0;
      customState.startTime = Date.now();
    },

    // Stop debugger
    customStop: () => {
      if (customState.intervalId) {
        clearInterval(customState.intervalId);
        customState.intervalId = null;
      }
      if (customState.observer) {
        customState.observer.disconnect();
      }

    },
  };

})();

